class Solution {
    public String reverseWords(String s) {
        char[] chars = s.toCharArray();
        int left = 0;
        for (int right = 0; right <= chars.length; right++) {
            if (right == chars.length || chars[right] == ' ') {
                int l = left, r = right - 1;
                while (l < r) {
                    char temp = chars[l];
                    chars[l++] = chars[r];
                    chars[r--] = temp;
                }
                left = right + 1;
            }
        }
        return new String(chars);
    }
}
